def get_id(username):
    try:
        url = f"https://www.instagram.com/{username}/"
        headers = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
        }
        
        response = requests.get(url, headers=headers)
        match = re.search(r'"profilePage_(\d+)"', response.text)
        
        if match:
            user_id = match.group(1)
            return user_id
        else:
            return None
    except Exception as e:
        return None

def get_user_info(user_id):
    data = {
        'lsd': ''.join(random.choices(string.ascii_letters + string.digits, k=32)),
        'variables': json.dumps({
            'id': int(user_id)
        }),
        'doc_id': '27937681195819736'
    }
    headers = {
        'x-fb-lsd': data['lsd'],
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
    }
    try:
        response = requests.post('https://www.instagram.com/api/graphql', headers=headers, data=data)
        response_data = response.json()
        
        if 'data' in response_data and 'user' in response_data['data']:
            user = response_data['data']['user']
            username = user.get("username", "غير متوفر")
            
            user_info = {
                "username": username,
                "Id": user.get('id', "غير متوفر"),
                "full_name": user.get("full_name", "غير متوفر"),
                "followers": user.get("follower_count", 0),
                "following": user.get("following_count", 0),
                "posts": user.get("media_count", 0),
                "bio": user.get("biography", "لا يوجد"),
                "is_private": user.get("is_private", False),
                "is_verified": user.get("is_verified", False),
                "profile_pic_url": user.get("profile_pic_url", "")
            }
            
            return user_info
        else:
            return None
            
    except Exception as e:
        return None

def get_rest(username):
    try:
        headers_get = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36",
            "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7",
            "Accept-Language": "ar,en-US;q=0.9,en;q=0.8",
            "Connection": "keep-alive",
            "Upgrade-Insecure-Requests": "1",
        }

        with requests.Session() as session:
            res_get = session.get("https://www.instagram.com/accounts/password/reset/?hl=ar")
            html = res_get.text

            lsd = re.search(r'\"LSD\",\[\],\{\"token\":\"(.*?)\"\}', html).group(1) if re.search(r'\"LSD\",\[\],\{\"token\":\"(.*?)\"\}', html) else ""
            spin_r = re.search(r'\"rev\":(\d+)', html).group(1) if re.search(r'\"rev\":(\d+)', html) else "1035687054"
            jazoest = re.search(r'name=\"jazoest\" value=\"(\d+)\"', html).group(1) if re.search(r'name=\"jazoest\" value=\"(\d+)\"', html) else ""

            variables = {
                "params": {
                    "event_request_id": str(uuid4()),
                    "next_uri": "",
                    "search_query": username,
                    "waterfall_id": str(uuid4())
                }
            }

            data = {
                "av": "0",
                "__d": "www",
                "__user": "0",
                "__a": "1",
                "__req": "1",
                "__hs": "20533.HYP:instagram_web_pkg.2.1..0.0",
                "dpr": "1",
                "__ccg": "GOOD",
                "__rev": spin_r,
                "lsd": lsd,
                "jazoest": jazoest,
                "__spin_r": spin_r,
                "__spin_b": "trunk",
                "__spin_t": str(int(time.time())),
                "fb_api_caller_class": "RelayModern",
                "fb_api_req_friendly_name": "CAAIGAccountSearchViewQuery",
                "variables": json.dumps(variables),
                "doc_id": "26178667145161478"
            }

            headers_post = {
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36",
                "Accept": "*/*",
                "Accept-Language": "en-US;q=0.9,en;q=0.8",
                "X-CSRFToken": session.cookies.get("csrftoken", ""),
                "X-IG-App-ID": "936619743392459",
                "X-ASBD-ID": "129477",
                "X-FB-LSD": lsd,
                "X-Requested-With": "XMLHttpRequest",
                "Origin": "https://www.instagram.com",
                "Referer": "https://www.instagram.com/accounts/password/reset/?hl=en",
                "Sec-Fetch-Dest": "empty",
                "Sec-Fetch-Mode": "cors",
                "Sec-Fetch-Site": "same-origin",
            }

            res_post = session.post("https://www.instagram.com/api/graphql", data=data, headers=headers_post)
            content = res_post.json()
            contact_points = content.get("data", {}).get("caa_ar_ig_account_search", {}).get("contact_points", [])
            
            if contact_points:
                rest = contact_points[0].get("contact_point", "")
                return rest
            else:
                return "لا يوجد"
    except Exception as po:
        return "خطأ"

def get_year_from_id(user_id):
    try:
        Id = int(user_id)
        if 1 < Id <= 1279000:
            return "2010"
        elif 1279000 < Id <= 17750000:
            return "2011"
        elif 17750000 < Id <= 279760000:
            return "2012"
        elif 279760000 < Id <= 900990000:
            return "2013"
        elif 900990000 < Id <= 1629010000:
            return "2014"
        elif 1629010000 < Id <= 1900000000:
            return "2014-2015"
        elif 1900000000 < Id <= 2500000000:
            return "2015"
        elif 2500000000 < Id <= 3713668786:
            return "2016"
        elif 3713668786 < Id <= 5699785217:
            return "2017"
        elif 5699785217 < Id <= 8507940634:
            return "2018"
        elif 8507940634 < Id <= 21254029834:
            return "2019"
        else:
            return "2020-2023"
    except (ValueError, TypeError):
        return "غير معروف"

